(10,	1,	'2026-03-23 11:07:26',	'2026-03-23 11:07:26',	'<!-- wp:paragraph -->\n<p><strong>1. Thời gian đổi trả</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>7 ngày đổi trả miễn phí:</strong> Áp dụng cho các lỗi từ nhà sản xuất hoặc giao sai mẫu mã/kích cỡ.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>30 ngày bảo hành/hỗ trợ:</strong> Cho các vấn đề phát sinh trong quá trình sử dụng (tùy dòng sản phẩm như giày, vợt, máy tập).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>2. Điều kiện đổi trả</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Để được chấp nhận, sản phẩm cần đáp ứng:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sản phẩm còn nguyên <strong>tem, mác, hộp</strong> và chưa qua sử dụng (trừ trường hợp lỗi sản xuất).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Có hóa đơn mua hàng hoặc thông tin số điện thoại đặt hàng trên hệ thống.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Sản phẩm không nằm trong danh mục \"Miễn đổi trả\" (thường là đồ lót thể thao, tất, hoặc hàng thanh lý xả kho).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>3. Quy trình thực hiện </strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Bước 1:</strong> Khách hàng liên hệ qua Hotline/Zalo của KhaSport kèm hình ảnh/video lỗi.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bước 2:</strong> Shop xác nhận trong vòng 24h.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bước 3:</strong> Khách gửi hàng về shop (hoặc shop cho shipper đến lấy tận nơi ).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bước 4:</strong> KhaSport gửi sản phẩm mới hoặc hoàn tiền sau 3-5 ngày làm việc.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>4. Chi phí vận chuyển</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Lỗi do KhaSport (giao sai, hàng lỗi):</strong> Shop chịu 100% phí ship 2 chiều.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Nhu cầu cá nhân (đổi size, đổi mẫu do không thích):</strong> Khách hàng hỗ trợ phí ship hoặc chia đôi tùy chính sách ưu đãi của bạn.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>5. Phương thức hoàn tiền</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Hoàn tiền qua tài khoản ngân hàng hoặc ví điện tử.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Hoàn bằng <strong>Voucher giảm giá</strong> cho lần mua sau.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->',	'Chính sách hoàn tiền và trả hàng',	'',	'publish',	'closed',	'closed',	'',	'refund_returns',	'',	'',	'2026-03-23 11:07:26',	'2026-03-23 11:07:26',	'',	0,	'http://khasport.local/?page_id=10',	0,	'page',	'',	0),
